local base_dir = "./files/"
local allowed_files = {
    "example.txt",
    "subdir/example2.txt"
}

local function canonicalize_path(path)
    local resolved_path = require("path").resolve(base_dir, path)
    if not resolved_path or resolved_path:find("^" .. base_dir) ~= 1 then
        return nil
    end
    return resolved_path
end

local filename = ngx.var.arg_filename
if not filename then
    ngx.say("Filename is required")
    ngx.exit(400)
end

local canonicalized_path = canonicalize_path(filename)
if not canonicalized_path then
    ngx.say("Invalid file path")
    ngx.exit(403)
end

if not allowed_files[filename] then
    ngx.say("File not allowed")
    ngx.exit(403)
end

local file, err = io.open(canonicalized_path, "r")
if not file then
    ngx.say("Error opening file: ", err)
    ngx.exit(500)
end

ngx.header["Content-Type"] = "application/octet-stream"
while true do
    local data = file:read(8192)
    if not data then break end
    ngx.say(data)
end

file:close()